```cpp
#include <vector>
#include <priority_queue>
#include <tuple>
#include <climits>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    vector<vector<tuple<long long, long long, long long>>> adj(n);
    for (auto& e : edges) {
        long long u = e[0];
        long long v = e[1];
        long long s = e[2];
        long long e_end = e[3];
        adj[u].push_back({v, s, e_end});
    }

    vector<long long> dist(n, LLONG_MAX);
    dist[0] = 0;

    priority_queue<pair<long long, int>, vector<pair<long long, int>>> pq;
    pq.push({0, 0});

    while (!pq.empty()) {
        auto [current_time_neg, u] = pq.top();
        long long current_time = -current_time_neg;
        pq.pop();

        if (u == n - 1) {
            return current_time;
        }

        if (current_time > dist[u]) {
            continue;
        }

        for (auto& [v, s, e_end] : adj[u]) {
            long long t = max(current_time, s);
            if (t > e_end) {
                continue;
            }
            long long new_time = t + 1;
            if (new_time < dist[v]) {
                dist[v] = new_time;
                pq.push({-new_time, v});
            }
        }
    }

    return -1;
}
```

